import React, { useEffect, useRef, useState } from "react";
import "./Hero.css";

export default function Hero({ onLaunchApp, onHowItWorks }) {
    const [scrollY, setScrollY] = useState(0);
    const heroRef = useRef(null);

    useEffect(() => {
        const fn = () => setScrollY(window.scrollY);
        window.addEventListener("scroll", fn, { passive: true });
        return () => window.removeEventListener("scroll", fn);
    }, []);

    // Parallax values
    const bgY    = scrollY * 0.4;
    const textY  = scrollY * 0.15;
    const wordY  = scrollY * -0.08;

    return (
        <section className="hero" ref={heroRef}>

            {/* Background image with parallax */}
            <div
                className="hero__bg"
                style={{ transform: `translateY(${bgY}px) scale(1.15)` }}
            />
            <div className="hero__overlay" />

            {/* Ferrari-style massive background word */}
            <div
                className="hero__bg-word"
                style={{ transform: `translateY(${wordY}px)` }}
            >
                IMMUTABLE
            </div>

            {/* Main content */}
            <div
                className="hero__content"
                style={{ transform: `translateY(${textY}px)` }}
            >
                <div className="hero__eyebrow">
                    <span className="hero__eyebrow-dot" />
                    Blockchain · IPFS · Academic Priority
                </div>

                <h1 className="hero__h1">
                    <span className="hero__h1-line hero__h1-line--1">Establish</span>
                    <span className="hero__h1-line hero__h1-line--2">
            Your <em>Research</em>
          </span>
                    <span className="hero__h1-line hero__h1-line--3">Priority.</span>
                </h1>

                <p className="hero__desc">
                    The world's first decentralised academic authorship system.
                    Your paper, timestamped forever — no institution required.
                </p>

                <div className="hero__actions">
                    <button className="hero__btn-main" onClick={onLaunchApp}>
                        <span>Register a Paper</span>
                        <span className="hero__btn-arrow">→</span>
                    </button>
                    <button className="hero__btn-ghost" onClick={onHowItWorks}>
                        How It Works
                    </button>
                </div>
            </div>

            {/* Stats bar at bottom */}
            <div className="hero__stats">
                {[
                    { val: "SHA-256",    label: "Content Hashing" },
                    { val: "EVM",        label: "Smart Contract Layer" },
                    { val: "IPFS",       label: "Decentralised Storage" },
                    { val: "Polygon",    label: "Blockchain Network" },
                ].map(({ val, label }) => (
                    <div className="hero__stat" key={label}>
                        <div className="hero__stat-val">{val}</div>
                        <div className="hero__stat-label">{label}</div>
                    </div>
                ))}
            </div>

            {/* Scroll indicator */}
            <div className="hero__scroll">
                <div className="hero__scroll-track">
                    <div className="hero__scroll-thumb" />
                </div>
                <span className="hero__scroll-text">Scroll</span>
            </div>
        </section>
    );
}
